var atMostNGivenDigitSet = function(digits, n) {
    const s = String(n);
    const L = s.length;
    const d = digits.length;
    let total = 0;
    // Numbers with fewer digits than L
    let pw = 1;
    for (let len = 1; len < L; len++) {
        pw *= d;
        total += pw;
    }
    // Numbers with exactly L digits
    for (let i = 0; i < L; i++) {
        const ch = s[i];
        let countLess = 0;
        for (const dig of digits) {
            if (dig < ch) countLess++;
        }
        const remaining = L - 1 - i;
        let placeValue = 1;
        for (let r = 0; r < remaining; r++) placeValue *= d;
        total += countLess * placeValue;
        if (!digits.includes(ch)) return total;
    }
    return total + 1;
};
